import type {
  DataTableCustomSortingFn,
  DataTableSortingColumnDef,
} from './sorting-types.js';
import type { DataTableDisplayColumnDef } from '../../public.api.js';
import type { DataTableColumnType } from '../ColumnTypes/column-types-types.js';

export function applySortTypes<TData, TValue>(
  column: DataTableDisplayColumnDef<TData, TValue>,
):
  | {
      sortType?: DataTableSortingColumnDef<TData, TValue>['sortType'];
    }
  | {
      customSortingFn?: DataTableCustomSortingFn<TValue>;
    } {
  if (column.disableSorting) {
    return {};
  }

  // user defined sort type
  if (column.sortType !== undefined) {
    if (typeof column.sortType === 'function') {
      return { customSortingFn: column.sortType };
    }
    return {
      sortType: column.sortType,
    };
  }

  // sorting based on column type
  return {
    sortType: getSortType(column.columnType),
  };
}

/** Gets sorting function for each of the different column types so the values are sorted correctly. */
function getSortType(columnType?: DataTableColumnType) {
  switch (columnType) {
    case 'number':
    case 'bit':
    case 'long':
    case 'meterbar':
      return 'number';
    // DEPRECATION: [APPDEV-16044] BREAKING-CHANGE: Remove 'date' columnType.
    case 'date':
    case 'datetime':
      return 'datetime';
    default:
      return 'text';
  }
}
